sql:
SELECT backer_id, reward_id, claimed_at, shipped_at, carrier
FROM backer_rewards
WHERE tracking_number = '123456789' AND carrier = 'FedEx';

SELECT * 
FROM project_updates
WHERE update_title IS NOT NULL;

SELECT project_id, AVG(pledged_amount) AS average_pledge, SUM(pledged_amount) AS total_pledged
FROM backers
GROUP BY project_id;

external_knowledge:
- "Generous pledgers" refers to backers who contribute a high average amount of money. ;
- "Dozen supporters" means more than 10 backers in this context. ;
- The success rate is determined as the total pledged amount divided by the number of backers. ;

sql:
SELECT reward_id, COUNT(*)
FROM backer_rewards
GROUP BY reward_id;

external_knowledge:
- "vibrant gardens" refers to projects;
- "bees" symbolizes backers;
- "blooms" represents the project's appeal;
- "nectar" is a metaphor for the pledged amount;
- "richness of their nectar harvest" is the total amount pledged by all backers.

sql:
SELECT u.user_name, b.pledged_at, b.pledged_usd > (SELECT AVG(pledged_usd) FROM backers) AS above_average
FROM backers b
INNER JOIN users u ON b.user_id = u.user_id;

SELECT c.category_name, sc.sub_category_name
FROM categories c
JOIN sub_categories sc ON c.category_id = sc.category_id;

SELECT image_url
FROM project_images
WHERE image_id = 0;

SELECT backers.backer_note, rewards.reward_title, rewards.reward_amount
FROM backers
JOIN rewards ON backers.reward_id = rewards.reward_id;

external_knowledge:
- "Navigators" refers to users whose role is 'backer';
- "Rivers" are symbolic of the individual projects each backer has pledged to;
- "Oceans" symbolize parent categories, and "seas" represent specific categories;
- "Miles" metaphorically represent the amount pledged by each backer.

sql:
SELECT users.user_id, users.user_name, countries.country_name
FROM users
JOIN countries ON users.preferred_language = countries.country_code;

SELECT DISTINCT user_name, email
FROM users
WHERE role = 'backer';

SELECT DISTINCT T1.user_name
FROM users AS T1
INNER JOIN backers AS T2 ON T1.user_id = T2.user_id;
